VALUES
  ('optometrist-moex-02594', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '許多低視力幼兒時常能觀察到眼球震顫（nystagmus），有關兒童眼球震顫之敘述，下列何者正確？', '["眼球震顫方向分為水平方向及垂直方向兩種，無其他方向", "眼球震顫不因注視方向而改變頻率、震幅", "眼球震顫相關的眼睛疾病很多，包含白內障、青光眼、視網膜病變等", "使用優先注視法（preferential looking）測量一位眼球震顫幼兒的視力，若患者有水平性的眼球震顫，則 雙手舉出卡片時應該要依水平方向排列"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02595', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '市售的一支望遠鏡標示為10×25 6.3°，代表下列何種規格？', '["望遠鏡總長度為10 cm，放大倍率為25，及對近焦為6.3 m", "放大倍率為10，望遠鏡總長度為25 cm，及視角為6.3°", "放大倍率為10，目鏡直徑為25 mm，及視角為6.3°", "放大倍率為10，物鏡直徑為25 mm，及視角為6.3°"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02596', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關圓錐角膜的低視力患者，下列敘述何者錯誤？', '["圓錐角膜好發於兒童或青少年", "圓錐角膜可能有複視情形", "作為視覺復健的輔具，隱形眼鏡一般比眼鏡更有效果", "屈光異常常為高度散光合併高度遠視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02597', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '臨床上，低視力病患在申請各項輔具時，大抵會依下列那一種順序來考量：①視覺類輔具  ②觸覺類輔', '["聽覺類輔具", "", "→", "→"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02598', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '中途因疾病或意外導致視覺功能缺損的病患，驗光師對病患未來工作的態度，下列敍述何者較為合適？', '["以協助換工作並提供新工作環境所需的視覺輔具協助為第一目標", "以協助病患回到原來的工作崗位為優先目標", "應暫緩工作，立即轉介社會局進行補助津貼的申請", "應轉介病患學習按摩的課程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02599', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '對低視力學生的輔具安排，下列敍述何者正確？ 甲生：右眼矯正後視力0.01，左眼矯正後視力0.3，視野正常 乙生：左右眼矯正後視力1.2，中央視野小於20度 丙生：左右眼矯正後視力0.03，視野正常 丁生：左右眼雖被定義全盲，仍可在5 cm～10 cm處勉強數手指', '["甲生可以使用望遠鏡做黑板抄寫，並用放大鏡看課本的文字", "乙生無輔具可以使用，需訓練其視物的技巧", "丙生與丁生均需以點字代替以眼睛閱讀的方式", "丙生視力太差，要減少使用眼睛的頻率"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02600', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關棘狀阿米巴原蟲（Acanthamoeba spp.）造成角膜潰瘍的敘述，下列何者錯誤？', '["初期相對於其他臨床症狀疼痛感極輕", "初期常誤診為單純疱疹角膜炎", "較常見於配戴角膜塑型片或軟式隱形眼鏡者", "角膜神經束膜炎（corneal perineuritis）為其特徵"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02601', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '對於新生兒有先天性角膜混濁之檢查，下列何者對患者立即病情處理最重要？', '["眼壓", "眼軸長短", "角膜直徑", "屈光度數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02602', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關Vogt-Koyanagi-Harada氏症候群之敘述，下列何者錯誤？', '["前驅期為腦膜炎、耳鳴、眩暈及耳聾", "可發現雙側肉芽腫性葡萄膜炎", "恢復期可見局部禿頭、白髮症及白化症", "目前沒有藥物可以治療"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02603', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '一個 9 歲男孩有過敏體質，每年季節交替時會有結膜炎的症狀，一週以來病人主訴視力模糊，經細隙燈 檢查雙眼上眼瞼結膜均有巨大乳突，下列何種病徵較不容易發生於此男孩？', '["上角膜血管翳（vascular pannus）及點狀表皮缺損（punctuate epithelial erosions）", "盾形表皮潰瘍（shield ulcer）", "輪部濾泡（limbal follicles）", "結膜沾黏（conjunctival symblepharon）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "f9015033fb91", "answer_pdf_sha1": "27b1f78737a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
